// ✗ Error — two root elements
function Profile() {
  return (
    <h1>Alice</h1>
    <p>Engineer</p>
  );
}

// ✔ Wrapper div
function Profile() {
  return (
    <div>
      <h1>Alice</h1>
      <p>Engineer</p>
    </div>
  );
}

// ✔ Fragment (preferred when div would pollute the DOM)
function Profile() {
  return (
    <>
      <h1>Alice</h1>
      <p>Engineer</p>
    </>
  );
}

// ✔ Named Fragment (needed when you need a key prop on the fragment)
import { Fragment } from 'react';
function Profile() {
  return (
    <Fragment>
      <h1>Alice</h1>
      <p>Engineer</p>
    </Fragment>
  );
}

const user = { name: 'Alice', score: 42 };

function ScoreCard() {
  return (
    <div>
      <h2>{user.name}</h2>              {/* variable */}
      <p>Score: {user.score * 2}</p>    {/* arithmetic */}
      <p>Grade: {user.score >= 50 ? 'Pass' : 'Fail'}</p> {/* ternary */}
      <p>Upper: {user.name.toUpperCase()}</p>  {/* method call */}
    </div>
  );
}

// ✗ if-statement inside JSX — syntax error
function Status({ isOnline }) {
  return <p>{if (isOnline) { 'Online' } else { 'Offline' }}</p>;
}

// ✔ ternary (an expression)
function Status({ isOnline }) {
  return <p>{isOnline ? 'Online' : 'Offline'}</p>;
}

// ✔ logical AND (short-circuit)
function Status({ isOnline }) {
  return <p>{isOnline && 'Online'}</p>;
}

// ✔ extract to variable (if/else then use variable)
function Status({ isOnline }) {
  let label;
  if (isOnline) {
    label = <strong>Online</strong>;
  } else {
    label = 'Offline';
  }
  return <p>{label}</p>;
}

// String literal — use quotes
<img src="/logo.png" alt="Company logo" />

// Dynamic value — use curly braces
const logoUrl = '/logo.png';
<img src={logoUrl} alt={company.name + ' logo'} />

// Boolean attributes: these are equivalent
<input disabled={true} />
<input disabled />          // JSX shorthand — same thing
<input disabled={false} />  // not disabled

function Form() {
  return (
    <div>
      {/* This is a JSX comment — invisible in the DOM */}
      <label htmlFor="email">Email</label>
      <input
        id="email"
        type="email"
        // This line comment works only outside JSX tags
      />
    </div>
  );
}

// ✗ CSS string — not valid in JSX
<div style="color: red; font-size: 16px;">...</div>

// ✔ Object with camelCase properties
<div style={{ color: 'red', fontSize: 16 }}>...</div>
//          ^outer {} = expression context
//           ^inner {} = the object literal

// Better: extract the object (less visual noise)
const cardStyle = {
  backgroundColor: '#fff',
  padding: '1rem',
  borderRadius: 8,        // treated as 8px
};

<div style={cardStyle}>...</div>

function Input({ label, ...inputProps }) {
  // inputProps contains everything except label
  return (
    <div>
      <label>{label}</label>
      <input {...inputProps} />
    </div>
  );
}

// Caller
<Input
  label="Email"
  type="email"
  placeholder="alice@example.com"
  required
/>

// ✗ ASI inserts a semicolon after return — component returns undefined!
function Card() {
  return
    <div>Hello</div>;
}

// ✔ Parentheses disable ASI
function Card() {
  return (
    <div>Hello</div>
  );
}

const items = [
  { id: 1, name: 'Apple' },
  { id: 2, name: 'Banana' },
  { id: 3, name: 'Cherry' },
];

function FruitList() {
  return (
    <ul>
      {items.map(item => (
        <li key={item.id}>{item.name}</li>
      ))}
    </ul>
  );
}

// JSX in a variable
const heading = <h1>Hello</h1>;

// JSX in an array
const rows = users.map(u => <tr key={u.id}><td>{u.name}</td></tr>);

// JSX passed as a prop
<Modal title={<h2>Confirm delete?</h2>}>
  <p>This cannot be undone.</p>
</Modal>

// JSX returned early
function Profile({ user }) {
  if (!user) return <p>Loading...</p>;
  return <div>{user.name}</div>;
}

// React 16 and below — explicit import required
import React from 'react';

function Hello() {
  return <h1>Hello</h1>;
}

// React 17+ with new JSX transform — no import needed
function Hello() {
  return <h1>Hello</h1>;
}

// ✗ SyntaxError: Adjacent JSX elements must be wrapped
return (
  <h1>Title</h1>
  <p>Body</p>
);

// ✔ Wrap in Fragment
return (
  <>
    <h1>Title</h1>
    <p>Body</p>
  </>
);

// ✗ Warning: Invalid DOM property 'class'. Did you mean 'className'?
<div class="container">...</div>

// ✔ Correct
<div className="container">...</div>

// These render nothing:
{null}       // ← renders nothing
{undefined}  // ← renders nothing
{false}      // ← renders nothing

// These DO render:
{0}          // ← renders the number 0 (common gotcha!)
{''}         // ← renders empty string

// Common gotcha with &&:
const count = 0;
return <div>{count && <Badge />}</div>; // renders "0" not nothing!

// Fix: convert to boolean first
return <div>{count > 0 && <Badge />}</div>; // renders nothing when 0
// or
return <div>{!!count && <Badge />}</div>;

// These look like they have a space, but they don't:
<span>Hello</span>
<span>World</span>
// Renders: HelloWorld

// Add a literal space character:
<span>Hello</span>{' '}
<span>World</span>
// Renders: Hello World

function ProductCard({ product, onAddToCart }) {
  const { name, price, inStock, tags } = product;

  const badgeStyle = {
    backgroundColor: inStock ? '#dcfce7' : '#fee2e2',
    color: inStock ? '#14532d' : '#991b1b',
    padding: '2px 8px',
    borderRadius: 4,
  };

  return (
    <div className="product-card">
      {/* Product header */}
      <h2>{name}</h2>

      <span style={badgeStyle}>
        {inStock ? 'In stock' : 'Out of stock'}
      </span>

      <p>Price: ${price.toFixed(2)}</p>

      {/* Tags list */}
      {tags.length > 0 && (
        <ul className="tags">
          {tags.map(tag => (
            <li key={tag}>{tag}</li>
          ))}
        </ul>
      )}

      <button
        onClick={() => onAddToCart(product)}
        disabled={!inStock}
        aria-label={`Add ${name} to cart`}
      >
        Add to cart
      </button>
    </div>
  );
}
